    public static int romanToInt(String s) {
        if (s == null || s.isEmpty()) {
            return 0;
        }
        Map<Character, Integer> romanMap = new HashMap<>();
        romanMap.put('I', 1);
        romanMap.put('V', 5);
        romanMap.put('X', 10);
        romanMap.put('L', 50);
        romanMap.put('C', 100);
        romanMap.put('D', 500);
        romanMap.put('M', 1000);
        int total = 0;
        int n = s.length();
        for (int i = 0; i < n; i++) {
            char c = s.charAt(i);
            if (!romanMap.containsKey(c)) {
                return 0;
            }
            int val = romanMap.get(c);
            if (i + 1 < n && romanMap.containsKey(s.charAt(i + 1)) && romanMap.get(s.charAt(i + 1)) > val) {
                total -= val;
            } else {
                total += val;
            }
        }
        return total;
    }
